text:
{
  "formal_minutes": {
    "confirmed_decisions": [
      {
        "topic": "공개 릴리스 타깃",
        "decision": "스모크 테스트가 통과하면 금요일 15:00 KST에 공개 릴리스를 진행한다."
      },
      {
        "topic": "packageName 불일치 처리",
        "decision": "packageName 불일치가 나오면 먼저 패키지 설정을 확인하고, 계약 자체가 잘못된 경우에만 smoke-theme-pack.mjs를 검토한다."
      }
    ],
    "rejected_proposals": [
      {
        "proposal": "수요일 공개 릴리스",
        "proposed_by": "Seoyeon",
        "reason": "스모크 테스트 통과가 먼저 필요하다."
      },
      {
        "proposal": "smoke-theme-pack.mjs가 packageName 불일치를 무시하도록 변경",
        "proposed_by": "Hara",
        "reason": "우선 패키지 설정을 확인하기로 했다."
      }
    ],
    "internal_stretch_goals": [
      {
        "item": "수요일 공개 릴리스 시도",
        "note": "내부 스트레치 목표이며 대외 확정 일정은 아니다."
      }
    ],
    "risks": [
      {
        "risk": "잘못된 tarball 경로는 릴리스를 지연시킬 수 있다.",
        "impact": "릴리스 지연"
      },
      {
        "risk": "README 설치 단계가 오래되면 릴리스 노트가 사용자를 오도할 수 있다.",
        "impact": "사용자 안내 오류"
      }
    ],
    "open_questions": [
      {
        "question": "최종 릴리스 승인 권한자는 누구인가?"
      },
      {
        "question": "릴리스 노트에 내부 수요일 스트레치 목표를 언급할 것인가?"
      }
    ],
    "non_decisions": [
      {
        "item": "README 설치 단계 검토",
        "status": "owner 미배정, 목요일까지 가능하면 검토"
      },
      {
        "item": "고객 또는 외부 파트너 지정",
        "status": "특정되지 않음"
      }
    ]
  },
  "action_items": [
    {
      "owner": "Minjun",
      "task": "스모크 테스트를 다시 실행하고 결과를 공유한다.",
      "due": "금요일 10:00 KST",
      "status": "예정",
      "source_certainty": "확정"
    },
    {
      "owner": "Doyun",
      "task": "실패 triage 노트를 action_items.md에 작성한다.",
      "due": "금요일 12:00 KST",
      "status": "예정",
      "source_certainty": "확정"
    },
    {
      "owner": "Hara",
      "task": "Minjun의 스모크 결과 이후 생성된 tarball 경로를 확인한다.",
      "due": null,
      "status": "의존 대기",
      "source_certainty": "확정"
    }
  ],
  "followup_note": {
    "next_checks": [
      "Minjun의 스모크 테스트 결과",
      "생성된 tarball 경로",
      "README 설치 단계 검토 담당자 지정 여부",
      "최종 릴리스 승인 권한자",
      "릴리스 노트에 내부 수요일 스트레치 목표를 넣을지 여부"
    ],
    "do_not_invent": [
      "고객명 또는 외부 파트너명",
      "예산",
      "보안 사고",
      "운영 장애",
      "법적 승인 요구사항",
      "확정되지 않은 날짜",
      "미배정 소유자"
    ]
  },
  "non_invention_rules": [
    "고객명 또는 외부 파트너명을 추정하지 않는다.",
    "예산을 추가하지 않는다.",
    "보안 사고를 추가하지 않는다.",
    "운영 장애를 추가하지 않는다.",
    "법적 승인 요구사항을 추가하지 않는다.",
    "owner를 임의로 배정하지 않는다.",
    "확정되지 않은 날짜나 마감일을 만들어내지 않는다.",
    "내부 스트레치 목표를 대외 확정 일정으로 바꾸지 않는다."
  ]
}
